INSERT INTO forms (title, description, uuid, fields) VALUES ('Feedback Form', 'Please share your thoughts to help us improve.', '0198ab3f-bcdd-43f5-a2ae-96b572c607d0', '[{"id":"field_b51b1e6c","type":"dropdown-multi","label":"1. Which services do you currently receive from us?","required":true,"options":["Corp Tax Registration / Amendments","VAT Registration / Amendments","CT Filing","VAT Filing","Book Keeping & Auditing","POA","Biz Set up / License Renewal","Visa Services","Business account opening","Other"]},{"id":"field_4550476a","type":"radio","label":"2. How satisfied are you with the quality of our services?","required":true,"options":["Very Satisfied (4)","Satisfied (3)","Neutral (2)","Unsatisfied (1)"]},{"id":"field_1324efd2","type":"radio","label":"3. How would you rate our team’s responsiveness to your queries?","required":true,"options":["Excellent (4)","Good (3)","Average (2)","Poor (1)"]},{"id":"field_180ecbb4","type":"radio","label":"4. Are the reports, filings, and documents delivered on time?","required":true,"options":["Always (4)","Usually (3)","Sometimes (2)","Rarely (1)"]},{"id":"field_506ea11c","type":"radio","label":"5. How clear and helpful is our communication regarding tax and compliance matters?","required":true,"options":["Very Clear (4)","Clear (3)","Average (2)","Not Clear (1)"]},{"id":"field_ec279439","type":"radio","label":"6. Do you feel our services help you stay compliant with UAE tax regulations?","required":true,"options":["Yes, definitely (4)","Mostly (3)","Somewhat (2)","Not really (1)"]},{"id":"field_2a042136","type":"textarea","label":"7. Is there any additional service you would like us to offer?","required":false},{"id":"field_755ae8bb","type":"textarea","label":"8. What can we improve in our services? Any comments or suggestions?","required":false}]');
